import AsyncStorage from "@react-native-async-storage/async-storage";
import {
  NavigationContainer,
  DefaultTheme,
  CommonActions,
} from "@react-navigation/native";
import { createNativeStackNavigator } from "@react-navigation/native-stack";

const STORAGE_KEYS = {
  AUTH: "@auth/session",
};

const AuthStack = createNativeStackNavigator();
const AppStack = createNativeStackNavigator();

const initialAuthState = {
  isBootstrapping: true,
  token: null,
  user: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case "BOOTSTRAP_DONE":
      return {
        ...state,
        isBootstrapping: false,
        token: action.payload?.token ?? null,
        user: action.payload?.user ?? null,
      };
    case "SIGN_IN":
      return {
        ...state,
        token: action.payload.token,
        user: action.payload.user,
      };
    case "SIGN_OUT":
      return {
        ...state,
        token: null,
        user: null,
      };
    case "UPDATE_USER":
      return {
        ...state,
        user: action.payload,
      };
    default:
      return state;
  }
}

async function saveSession(session) {
  await AsyncStorage.setItem(STORAGE_KEYS.AUTH, JSON.stringify(session));
}

async function loadSession() {
  const raw = await AsyncStorage.getItem(STORAGE_KEYS.AUTH);
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") return null;
    const { token, user } = parsed;
    if (!token) return null;
    return { token, user: user ?? null };
  } catch {
    return null;
  }
}

async function clearSession() {
  await AsyncStorage.removeItem(STORAGE_KEYS.AUTH);
}

async function fakeLoginApi({ email, password }) {
  await new Promise((r) => setTimeout(r, 700));
  if (!email || !password) {
    const err = new Error("Missing credentials");
    err.code = "MISSING";
    throw err;
  }
  if (password.length < 4) {
    const err = new Error("Invalid credentials");
    err.code = "INVALID";
    throw err;
  }
  const token = "token_" + Math.random().toString(36).slice(2);
  const user = {
    id: "user_" + Math.random().toString(36).slice(2, 8),
    name: email.split("@")[0] || "User",
    email,
  };
  return { token, user };
}

async function fakeFetchMeApi(token) {
  await new Promise((r) => setTimeout(r, 350));
  if (!token) throw new Error("No token");
  return null;
}

const AuthContext = React.createContext(null);

