export default function App() {
  const [state, dispatch] = useReducer(authReducer, initialAuthState);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const session = await loadSession();
      if (cancelled) return;

      if (session?.token) {
        try {
          await fakeFetchMeApi(session.token);
        } catch {
          await clearSession();
          dispatch({ type: "BOOTSTRAP_DONE", payload: null });
          return;
        }
      }

      dispatch({ type: "BOOTSTRAP_DONE", payload: session });
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const auth = useMemo(() => {
    return {
      token: state.token,
      user: state.user,
      signIn: async ({ email, password }) => {
        const result = await fakeLoginApi({ email, password });
        const session = { token: result.token, user: result.user };
        await saveSession(session);
        dispatch({ type: "SIGN_IN", payload: session });
      },
      signOut: async () => {
        await clearSession();
        dispatch({ type: "SIGN_OUT" });
      },
      refreshUser: async () => {
        if (!state.token) throw new Error("Not authenticated");
        const updatedUser = { ...(state.user ?? {}), lastRefreshedAt: Date.now() };
        const session = { token: state.token, user: updatedUser };
        await saveSession(session);
        dispatch({ type: "UPDATE_USER", payload: updatedUser });
      },
    };
  }, [state.token, state.user]);

  if (state.isBootstrapping) return <SplashScreen />;

  return (
    <AuthContext.Provider value={auth}>
      <NavigationContainer theme={DefaultTheme}>
        {state.token ? <AppNavigator /> : <AuthNavigator />}
      </NavigationContainer>
    </AuthContext.Provider>
  );
}

